import React, { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "motion/react";
import { Typography, useTheme, Box } from "@mui/material";
import { LuX } from "react-icons/lu";

const sampleData = {
  basic: [
    "Apple",
    "Banana",
