                animate={{
                  y: 250,
                  opacity: [0, 1, 1, 0],
                }}
                transition={{
                  duration: 2,
                  delay: meteor.delay,
                  ease: "linear",
                }}
                sx={{
                  position: "absolute",
                  width: "2px",
                  height: "20px",
                  background: `linear-gradient(to bottom, ${
                    theme.palette.mode === "dark" ? "#FFFFFF" : "#000000"
