                  boxShadow: `0 0 10px ${
                    theme.palette.mode === "dark" ? "#FFFFFF" : "#000000"
                  }`,
                  zIndex: 1,
                  willChange: "transform, opacity",
                }}
              />
            ))}
          </MotionCard>
        );

      case "dynamicOverlay":
        return (
          <MotionCard
            initial="initial"
            whileHover="hover"
            sx={{
              ...commonCardStyle,
              backgroundImage: `url('https://cdn.webshopapp.com/shops/268192/files/433182622/tommy-shelby.jpg')`,
              backgroundSize: "cover",
              backgroundPosition: "center",
              cursor: "pointer",
              overflow: "hidden",
              position: "relative",
              border: "1px solid",
              borderColor: theme.palette.divider,
              zIndex: 2,
            }}
          >
            <motion.div
              initial={{ opacity: 1 }}
              variants={{
                initial: { opacity: 1 },
                hover: { opacity: 0 },
              }}
              transition={{ duration: 0.5, ease: "easeInOut" }}
              style={{
                position: "absolute",
                inset: 0,
                backgroundSize: "cover",
                backgroundPosition: "center",
                zIndex: 1,
              }}
            />

            <motion.div
              variants={{
                initial: { opacity: 0 },
                hover: { opacity: 1 },
              }}
              transition={{ duration: 0.5, ease: "easeInOut" }}
              style={{
                position: "absolute",
                inset: 0,
                backgroundImage: `url('https://i.giphy.com/media/v1.Y2lkPTc5MGI3NjExdjBvZWV0MmgxYTR5dmtweDl5aG1oMTE3b25yYzQ1Y3EyMGN1cjRoMyZlcD12MV9pbnRlcm5hbF9naWZfYnlfaWQmY3Q9Zw/X3Zr6miqq2KuQ/giphy.gif')`,
                backgroundSize: "cover",
