              </motion.div>

              <Box
                sx={{
                  pt: 1,
                  px: 2,
                  flexGrow: 1,
                  display: "flex",
                  flexDirection: "column",
                  justifyContent: "space-between",
                }}
              >
                <Box
                  sx={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                    mb: 1,
                  }}
                >
                  <Typography
                    variant="body2"
                    fontWeight={500}
                    sx={{
                      display: "flex",
                      alignItems: "center",
                    }}
                  >
                    <RxImage
                      size={24}
                      style={{ marginRight: 8, color: "#FFC107" }}
