import React, { useState, useMemo, useRef, useEffect } from "react";
import {
  Typography,
  useTheme,
  Box,
  TextField,
  Button,
  InputAdornment,
  IconButton,
} from "@mui/material";
import {
  LuCalendar,
  LuChevronLeft,
  LuChevronRight,
  LuClock,
} from "react-icons/lu";

const DatePickerVariants = ({ variant = "single" }) => {
  const [selectedDate, setSelectedDate] = useState(null);
  const [startDate, setStartDate] = useState(null);
  const [endDate, setEndDate] = useState(null);
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [isOpen, setIsOpen] = useState(false);
  const [selectedTime, setSelectedTime] = useState({
    hour: "12",
    minute: "00",
    period: "PM",
  });
  const [calendarPosition, setCalendarPosition] = useState("bottom");

  const containerRef = useRef(null);
  const calendarRef = useRef(null);

  const theme = useTheme();
  const isDark = theme.palette.mode === "dark";

  const calculatePosition = () => {
    if (!containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const viewportHeight = window.innerHeight;
    const calendarHeight = 400;

    const spaceBelow = viewportHeight - rect.bottom;
    const spaceAbove = rect.top;

    if (spaceBelow < calendarHeight && spaceAbove > calendarHeight) {
      setCalendarPosition("top");
    } else {
      setCalendarPosition("bottom");
    }
  };

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (
        containerRef.current &&
        !containerRef.current.contains(event.target) &&
        calendarRef.current &&
        !calendarRef.current.contains(event.target)
      ) {
        setIsOpen(false);
      }
    };

    const handleScroll = () => {
      if (isOpen) {
        setIsOpen(false);
      }
    };

    if (isOpen) {
      document.addEventListener("mousedown", handleClickOutside);
      window.addEventListener("scroll", handleScroll, true);
      calculatePosition();
    }

    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
      window.removeEventListener("scroll", handleScroll, true);
    };
  }, [isOpen]);

  useEffect(() => {
    const handleResize = () => {
      if (isOpen) {
        calculatePosition();
      }
    };

    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, [isOpen]);

  const presets = useMemo(
    () => [
      {
        label: "Today",
        getValue: () => {
          const d = new Date();
          d.setHours(0, 0, 0, 0);
          return { start: d, end: new Date(d) };
        },
      },
      {
        label: "Yesterday",
        getValue: () => {
          const d = new Date();
          d.setDate(d.getDate() - 1);
          d.setHours(0, 0, 0, 0);
          const end = new Date(d);
          end.setHours(23, 59, 59, 999);
          return { start: d, end };
        },
      },
      {
        label: "This Week",
        getValue: () => {
          const date = new Date();
          const day = date.getDay();
          const start = new Date(date);
          start.setDate(date.getDate() - day);
          start.setHours(0, 0, 0, 0);
          const end = new Date();
          end.setHours(23, 59, 59, 999);
          return { start, end };
        },
      },
      {
        label: "Last 7 Days",
        getValue: () => {
          const end = new Date();
          end.setHours(23, 59, 59, 999);
          const start = new Date();
          start.setDate(end.getDate() - 6);
          start.setHours(0, 0, 0, 0);
          return { start, end };
        },
      },
      {
        label: "Last 30 Days",
        getValue: () => {
          const end = new Date();
          end.setHours(23, 59, 59, 999);
          const start = new Date();
          start.setDate(end.getDate() - 29);
          start.setHours(0, 0, 0, 0);
          return { start, end };
        },
      },
      {
        label: "This Month",
        getValue: () => {
          const date = new Date();
          const start = new Date(date.getFullYear(), date.getMonth(), 1);
          start.setHours(0, 0, 0, 0);
          const end = new Date();
          end.setHours(23, 59, 59, 999);
          return { start, end };
        },
      },
    ],
    []
  );

  const days = useMemo(() => {
    const year = currentMonth.getFullYear();
    const month = currentMonth.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const daysInPrevMonth = new Date(year, month, 0).getDate();

    const result = [];

    for (let i = firstDay - 1; i >= 0; i--) {
      result.push({
        day: daysInPrevMonth - i,
        isCurrentMonth: false,
        date: new Date(year, month - 1, daysInPrevMonth - i),
      });
    }

    for (let i = 1; i <= daysInMonth; i++) {
      result.push({
        day: i,
        isCurrentMonth: true,
        date: new Date(year, month, i),
      });
    }

    const remainingDays = 42 - result.length;
    for (let i = 1; i <= remainingDays; i++) {
      result.push({
        day: i,
        isCurrentMonth: false,
        date: new Date(year, month + 1, i),
      });
    }

    return result;
  }, [currentMonth]);

  const isSameDay = (date1, date2) => {
    if (!date1 || !date2) return false;
    const d1 = new Date(date1);
    const d2 = new Date(date2);
    d1.setHours(0, 0, 0, 0);
    d2.setHours(0, 0, 0, 0);
    return d1.getTime() === d2.getTime();
  };

  const isInRange = (date) => {
    if (!startDate || !endDate) return false;
    const checkDate = new Date(date);
    checkDate.setHours(0, 0, 0, 0);
    const start = new Date(startDate);
    start.setHours(0, 0, 0, 0);
    const end = new Date(endDate);
    end.setHours(0, 0, 0, 0);
    return checkDate >= start && checkDate <= end;
  };

  const isToday = (date) => isSameDay(date, new Date());

  const handleDateClick = (date) => {
    if (variant === "range" || variant === "presets") {
      if (!startDate || (startDate && endDate)) {
        setStartDate(date);
        setEndDate(null);
      } else {
        if (date < startDate) {
          setEndDate(startDate);
          setStartDate(date);
        } else {
          setEndDate(date);
        }
      }
    } else {
      setSelectedDate(date);
      if (variant !== "with-time") {
        setIsOpen(false);
      }
    }
  };

  const handlePresetClick = (preset) => {
    const value = preset.getValue();
    if (value.start && value.end) {
      setStartDate(value.start);
      setEndDate(value.end);
    } else {
      setSelectedDate(value);
      setIsOpen(false);
    }
  };

  const handleTimeChange = (field, value) => {
    if (value === "") {
      setSelectedTime({
        ...selectedTime,
        [field]: "",
      });
      return;
    }

    let numValue = value.replace(/\D/g, "");

    if (field === "hour") {
      let num = parseInt(numValue);
      if (num > 12) {
        numValue = "12";
      } else if (num < 1 && numValue.length === 2) {
        numValue = "01";
      }
    } else {
      let num = parseInt(numValue);
      if (num > 59) {
        numValue = "59";
      }
    }

    setSelectedTime({
      ...selectedTime,
      [field]: numValue,
    });
  };

  const formatDate = (date) => {
    if (!date) return "";
    return date.toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    });
  };

  const formatDateRange = () => {
    if (!startDate) return "";
    if (!endDate) return formatDate(startDate);
    return `${formatDate(startDate)} - ${formatDate(endDate)}`;
  };

  const formatDateTime = () => {
    if (!selectedDate) return "";
    return `${formatDate(selectedDate)} ${selectedTime.hour}:${selectedTime.minute} ${selectedTime.period}`;
  };

  const getInputValue = () => {
    switch (variant) {
      case "range":
      case "presets":
        return formatDateRange();
      case "with-time":
        return formatDateTime();
      default:
        return formatDate(selectedDate);
    }
  };

  const getPlaceholder = () => {
    switch (variant) {
      case "range":
        return "Select date range...";
      case "presets":
        return "Select or choose preset...";
      case "with-time":
        return "Select date and time...";
      default:
        return "Select date...";
    }
  };

  const getDescription = () => {
    switch (variant) {
      case "single":
        return "Standard calendar date picker";
      case "range":
        return "Select start and end dates";
      case "presets":
        return "Quick select with preset options";
      case "with-time":
        return "Combined date and time selection";
      default:
        return "Interactive date picker";
    }
  };

  const getDayStyle = (day) => {
    const isSelected = isSameDay(day.date, selectedDate);
    const isStart = isSameDay(day.date, startDate);
    const isEnd = isSameDay(day.date, endDate);
    const inRange = isInRange(day.date);
    const isCurrentDay = isToday(day.date);
    const shouldShowDate = day.isCurrentMonth || inRange || isStart || isEnd;

    return {
      aspectRatio: "1",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      fontSize: "14px !important",
      fontWeight: isCurrentDay ? "500 !important" : "400 !important",
      borderRadius: "8px",
      cursor: shouldShowDate ? "pointer" : "default",
      color: `${
        !shouldShowDate
          ? isDark
            ? "#333"
            : "#ccc"
          : isSelected || isStart || isEnd
            ? isDark
              ? "#000"
              : "#fff"
            : isDark
              ? "#fff"
              : "#000"
      } !important`,
      backgroundColor: `${
        isSelected || isStart || isEnd
          ? isDark
            ? "#fff"
            : "#000"
          : inRange
            ? isDark
              ? "rgba(255,255,255,0.1)"
              : "rgba(0,0,0,0.06)"
            : "transparent"
      } !important`,
      border: `${
        isCurrentDay && !isSelected && !isStart && !isEnd
          ? `1px solid ${isDark ? "#666" : "#999"}`
          : "1px solid transparent"
      } !important`,
      transition:
        "background-color 0.15s ease, transform 0.15s ease !important",
    };
  };

  const monthYear = currentMonth.toLocaleDateString("en-US", {
    month: "long",
    year: "numeric",
  });

  const renderCalendar = () => (
    <Box
      ref={calendarRef}
      sx={{
        position: "absolute !important",
        ...(calendarPosition === "top"
          ? {
              bottom: "calc(100% + 6px) !important",
            }
          : {
              top: "calc(100% + 6px) !important",
            }),
        left: "0 !important",
        right: "0 !important",
        bgcolor: `${isDark ? "#1a1a1a" : "#fff"} !important`,
        border: `1px solid ${isDark ? "#333" : "#e0e0e0"} !important`,
        borderRadius: "12px !important",
        p: "12px !important",
        boxShadow: "0 8px 32px rgba(0,0,0,0.12) !important",
        zIndex: "1000 !important",
      }}
    >
      {variant === "presets" && (
        <Box
          sx={{
            display: "flex !important",
            flexWrap: "wrap !important",
            gap: "4px !important",
            mb: "12px !important",
            pb: "12px !important",
            borderBottom: `1px solid ${isDark ? "#333" : "#e0e0e0"} !important`,
          }}
        >
          {presets.map((preset) => (
            <Button
              key={preset.label}
              onClick={() => handlePresetClick(preset)}
              disableRipple
              disableElevation
              sx={{
                p: "6px 10px !important",
                minWidth: "auto !important",
                minHeight: "auto !important",
                fontSize: "12px !important",
                fontWeight: "400 !important",
                color: `${isDark ? "#fff" : "#000"} !important`,
                bgcolor: `${isDark ? "rgba(255,255,255,0.05)" : "rgba(0,0,0,0.04)"} !important`,
                borderRadius: "6px !important",
                textTransform: "none !important",
                transition: "background-color 0.15s ease !important",
                whiteSpace: "nowrap !important",
                "&:hover": {
                  bgcolor: `${isDark ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.08)"} !important`,
                },
              }}
            >
              {preset.label}
            </Button>
          ))}
        </Box>
      )}

      <Box
        sx={{
          display: "flex !important",
          justifyContent: "space-between !important",
          alignItems: "center !important",
          mb: "12px !important",
        }}
      >
        <IconButton
          onClick={() =>
            setCurrentMonth(
              new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1)
            )
          }
          disableRipple
          sx={{
            p: "6px !important",
            borderRadius: "6px !important",
            color: `${isDark ? "#fff" : "#000"} !important`,
            bgcolor: "transparent !important",
            transition: "background-color 0.15s ease !important",
            "&:hover": {
              bgcolor: `${isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.06)"} !important`,
            },
          }}
        >
          <LuChevronLeft size={16} />
        </IconButton>
        <Typography
          sx={{
            fontSize: "14px !important",
            fontWeight: "500 !important",
            color: `${isDark ? "#fff" : "#000"} !important`,
          }}
        >
          {monthYear}
        </Typography>
        <IconButton
          onClick={() =>
            setCurrentMonth(
              new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1)
            )
          }
          disableRipple
          sx={{
            p: "6px !important",
            borderRadius: "6px !important",
            color: `${isDark ? "#fff" : "#000"} !important`,
            bgcolor: "transparent !important",
            transition: "background-color 0.15s ease !important",
            "&:hover": {
              bgcolor: `${isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.06)"} !important`,
            },
          }}
        >
          <LuChevronRight size={16} />
        </IconButton>
      </Box>

      <Box
        sx={{
          display: "grid !important",
          gridTemplateColumns: "repeat(7, 1fr) !important",
          gap: "2px !important",
          mb: "6px !important",
        }}
      >
        {["Su", "Mo", "Tu", "We", "Th", "Fr", "Sa"].map((day) => (
          <Typography
            key={day}
            sx={{
              fontSize: "12px !important",
              fontWeight: "500 !important",
              color: `${isDark ? "#666" : "#999"} !important`,
              textAlign: "center !important",
              py: "6px !important",
            }}
          >
            {day}
          </Typography>
        ))}
      </Box>

      <Box
        sx={{
          display: "grid !important",
          gridTemplateColumns: "repeat(7, 1fr) !important",
          gap: "4px !important",
        }}
      >
        {days.map((day, index) => (
          <Box
            key={`${day.date.getTime()}-${index}`}
            sx={getDayStyle(day)}
            onClick={() => handleDateClick(day.date)}
            onMouseEnter={(e) => {
              if (
                day.isCurrentMonth &&
                !isSameDay(day.date, selectedDate) &&
                !isSameDay(day.date, startDate) &&
                !isSameDay(day.date, endDate)
              ) {
                e.currentTarget.style.backgroundColor = isDark
                  ? "rgba(255,255,255,0.08)"
                  : "rgba(0,0,0,0.04)";
                e.currentTarget.style.transform = "scale(1.05)";
              }
            }}
            onMouseLeave={(e) => {
              if (
                day.isCurrentMonth &&
                !isSameDay(day.date, selectedDate) &&
                !isSameDay(day.date, startDate) &&
                !isSameDay(day.date, endDate) &&
                !isInRange(day.date)
              ) {
                e.currentTarget.style.backgroundColor = "transparent";
                e.currentTarget.style.transform = "scale(1)";
              }
            }}
          >
            {day.day}
          </Box>
        ))}
      </Box>

      {variant === "with-time" && selectedDate && (
        <Box
          sx={{
            display: "flex !important",
            alignItems: "center !important",
            justifyContent: "center !important",
            gap: "6px !important",
            mt: "12px !important",
            p: "10px !important",
            bgcolor: `${isDark ? "rgba(255,255,255,0.03)" : "rgba(0,0,0,0.02)"} !important`,
            borderRadius: "10px !important",
          }}
        >
          <LuClock size={14} color={isDark ? "#666" : "#999"} />
          <TextField
            value={selectedTime.hour}
            onChange={(e) => handleTimeChange("hour", e.target.value)}
            onBlur={(e) => {
              let value = e.target.value;
              if (value === "" || parseInt(value) < 1 || parseInt(value) > 12) {
                handleTimeChange("hour", "12");
              } else if (value.length === 1) {
                setSelectedTime({
                  ...selectedTime,
                  hour: value.padStart(2, "0"),
                });
              }
            }}
            inputProps={{ maxLength: 2 }}
            sx={{
              width: "42px !important",
              "& .MuiOutlinedInput-root": {
                height: "32px !important",
                bgcolor: `${isDark ? "rgba(255,255,255,0.03)" : "#fff"} !important`,
                borderRadius: "6px !important",
                transition: "border-color 0.15s ease !important",
                "& fieldset": {
                  borderColor: `${isDark ? "#333" : "#e0e0e0"} !important`,
                },
                "&:hover fieldset": {
                  borderColor: `${isDark ? "#444" : "#d0d0d0"} !important`,
                },
                "&.Mui-focused fieldset": {
                  borderColor: `${isDark ? "#555" : "#bbb"} !important`,
                  borderWidth: "1px !important",
                },
              },
              "& .MuiOutlinedInput-input": {
                p: "0 6px !important",
                textAlign: "center !important",
                color: `${isDark ? "#fff" : "#000"} !important`,
                fontSize: "14px !important",
                fontWeight: "400 !important",
              },
            }}
          />
          <Typography
            sx={{
              color: `${isDark ? "#666" : "#999"} !important`,
              fontSize: "12px !important",
            }}
          >
            :
          </Typography>
          <TextField
            value={selectedTime.minute}
            onChange={(e) => handleTimeChange("minute", e.target.value)}
            onBlur={(e) => {
              let value = e.target.value;
              if (value === "" || parseInt(value) > 59) {
                handleTimeChange("minute", "00");
              } else if (value.length === 1) {
                setSelectedTime({
                  ...selectedTime,
                  minute: value.padStart(2, "0"),
                });
              }
            }}
            inputProps={{ maxLength: 2 }}
            sx={{
              width: "42px !important",
              "& .MuiOutlinedInput-root": {
                height: "32px !important",
                bgcolor: `${isDark ? "rgba(255,255,255,0.03)" : "#fff"} !important`,
                borderRadius: "6px !important",
                transition: "border-color 0.15s ease !important",
                "& fieldset": {
                  borderColor: `${isDark ? "#333" : "#e0e0e0"} !important`,
                },
                "&:hover fieldset": {
                  borderColor: `${isDark ? "#444" : "#d0d0d0"} !important`,
                },
                "&.Mui-focused fieldset": {
                  borderColor: `${isDark ? "#555" : "#bbb"} !important`,
                  borderWidth: "1px !important",
                },
              },
              "& .MuiOutlinedInput-input": {
                p: "0 6px !important",
                textAlign: "center !important",
                color: `${isDark ? "#fff" : "#000"} !important`,
                fontSize: "14px !important",
                fontWeight: "400 !important",
              },
            }}
          />
          <Box sx={{ display: "flex !important", gap: "3px !important" }}>
            <Button
              onClick={() => setSelectedTime({ ...selectedTime, period: "AM" })}
              disableRipple
              disableElevation
              sx={{
                p: "6px 10px !important",
                minWidth: "auto !important",
                minHeight: "auto !important",
                fontSize: "12px !important",
                fontWeight: "500 !important",
                color:
                  selectedTime.period === "AM"
                    ? `${isDark ? "#000" : "#fff"} !important`
                    : `${isDark ? "#999" : "#666"} !important`,
                bgcolor: `${
                  selectedTime.period === "AM"
                    ? isDark
                      ? "#fff"
                      : "#000"
                    : "transparent"
                } !important`,
                border: "none !important",
                borderRadius: "6px !important",
                textTransform: "none !important",
                transition: "background-color 0.15s ease !important",
                "&:hover": {
                  bgcolor: `${
                    selectedTime.period === "AM"
                      ? isDark
                        ? "#fff"
                        : "#000"
                      : isDark
                        ? "rgba(255,255,255,0.05)"
                        : "rgba(0,0,0,0.04)"
                  } !important`,
                },
              }}
            >
              AM
            </Button>
            <Button
              onClick={() => setSelectedTime({ ...selectedTime, period: "PM" })}
              disableRipple
              disableElevation
              sx={{
                p: "6px 10px !important",
                minWidth: "auto !important",
                minHeight: "auto !important",
                fontSize: "12px !important",
                fontWeight: "500 !important",
                color:
                  selectedTime.period === "PM"
                    ? `${isDark ? "#000" : "#fff"} !important`
                    : `${isDark ? "#999" : "#666"} !important`,
                bgcolor: `${
                  selectedTime.period === "PM"
                    ? isDark
                      ? "#fff"
                      : "#000"
                    : "transparent"
                } !important`,
                border: "none !important",
                borderRadius: "6px !important",
                textTransform: "none !important",
                transition: "background-color 0.15s ease !important",
                "&:hover": {
                  bgcolor: `${
                    selectedTime.period === "PM"
                      ? isDark
                        ? "#fff"
                        : "#000"
                      : isDark
                        ? "rgba(255,255,255,0.05)"
                        : "rgba(0,0,0,0.04)"
                  } !important`,
                },
              }}
            >
              PM
            </Button>
          </Box>
        </Box>
      )}
    </Box>
  );

  return (
    <Box
      ref={containerRef}
      sx={{
        width: "100% !important",
        maxWidth: "320px !important",
        margin: "0 auto !important",
        position: "relative !important",
      }}
    >
      <Typography
        variant="body2"
        sx={{
          mb: "6px !important",
          textAlign: "center !important",
          fontSize: "13px !important",
          color: `${isDark ? "#999" : "#666"} !important`,
        }}
      >
        {getDescription()}
      </Typography>
      <Box sx={{ position: "relative !important" }}>
        <TextField
          fullWidth
          placeholder={getPlaceholder()}
          value={getInputValue()}
          onClick={() => {
            calculatePosition();
            setIsOpen(!isOpen);
          }}
          InputProps={{
            readOnly: true,
            startAdornment: (
              <InputAdornment
                position="start"
                sx={{ ml: "0 !important", mr: "0 !important" }}
              >
                <LuCalendar size={16} color={isDark ? "#666" : "#999"} />
              </InputAdornment>
            ),
          }}
          sx={{
            "& .MuiOutlinedInput-root": {
              height: "44px !important",
              bgcolor: `${isDark ? "rgba(255,255,255,0.03)" : "#fff"} !important`,
              borderRadius: "10px !important",
              cursor: "pointer !important",
              transition: "border-color 0.15s ease !important",
              "& fieldset": {
                borderColor: `${isDark ? "#333" : "#e0e0e0"} !important`,
              },
              "&:hover fieldset": {
                borderColor: `${isDark ? "#444" : "#d0d0d0"} !important`,
              },
              "&.Mui-focused fieldset": {
                borderColor: `${isDark ? "#555" : "#bbb"} !important`,
                borderWidth: "1px !important",
              },
            },
            "& .MuiOutlinedInput-input": {
              cursor: "pointer !important",
              color: `${isDark ? "#fff" : "#000"} !important`,
              fontSize: "14px !important",
              fontWeight: "400 !important",
              pl: "36px !important",
              pr: "12px !important",
            },
            "& .MuiInputAdornment-root": {
              position: "absolute !important",
              left: "12px !important",
            },
          }}
        />
        {isOpen && renderCalendar()}
      </Box>
    </Box>
  );
};

export default DatePickerVariants;

dialogs.code:
import React, { useState, useEffect } from "react";
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  Typography,
  Box,
  TextField,
  useTheme,
  Slide,
  Fade,
  Grow,
  useMediaQuery,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Divider,
  IconButton,
} from "@mui/material";
import {
  RxGear,
  RxDashboard,
  RxPerson,
  RxBell,
  RxChevronRight,
  RxCross2,
  RxCheck,
} from "react-icons/rx";
import { motion, AnimatePresence } from "motion/react";

const TransitionSlide = React.forwardRef(function Transition(props, ref) {
  return <Slide direction="up" ref={ref} {...props} />;
});

const TransitionFade = React.forwardRef(function Transition(props, ref) {
  return <Fade ref={ref} {...props} />;
});

const TransitionGrow = React.forwardRef(function Transition(props, ref) {
  return <Grow ref={ref} {...props} />;
});

const MotionBox = motion.create(Box);

const DialogVariants = ({ variant }) => {
  const [open, setOpen] = useState(false);
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down("sm"));
  const isTablet = useMediaQuery(theme.breakpoints.down("md"));

  const handleOpen = () => setOpen(true);
  const handleClose = () => setOpen(false);

  const isDark = theme.palette.mode === "dark";
  const textColor = isDark ? "#ffffff" : "#000000";
  const bgColor = isDark ? "#1a1a1a" : "#ffffff";
  const borderColor = isDark ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.1)";

  useEffect(() => {
    if (open && (variant === "notification" || variant === "info")) {
      const timer = setTimeout(() => {
        setOpen(false);
      }, 4000);
      return () => clearTimeout(timer);
    }
  }, [open, variant]);

  const getButtonText = () => {
    switch (variant) {
      case "slideUp":
        return "Slide Up";
      case "blur":
        return "Blur Modal";
      case "form":
        return "Form Dialog";
      case "info":
        return "Info Dialog";
      case "fullscreen":
        return "Fullscreen";
      case "sidebar":
        return "Sidebar";
      case "notification":
        return "Notification";
      default:
        return "Default";
    }
  };

  const commonDialogProps = {
    maxWidth: "sm",
    fullWidth: true,
    PaperProps: {
      sx: {
        borderRadius: 2,
        width: isMobile ? "90vw" : isTablet ? "80vw" : 480,
        maxWidth: isMobile ? "90vw" : 480,
        backgroundColor: bgColor,
        backgroundImage: "none",
        border: `1px solid ${borderColor}`,
        boxShadow: isDark
          ? "0 25px 50px -12px rgba(0, 0, 0, 0.8)"
          : "0 25px 50px -12px rgba(0, 0, 0, 0.25)",
      },
    },
  };

  const CloseButton = ({ onClick, style = {} }) => (
    <IconButton
      onClick={onClick}
      size="small"
      sx={{
        width: 32,
        height: 32,
        backgroundColor: isDark ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.1)",
        color: textColor,
        "&:hover": {
          backgroundColor: isDark ? "rgba(255,255,255,0.2)" : "rgba(0,0,0,0.2)",
        },
        ...style,
      }}
    >
      <RxCross2 size={16} />
    </IconButton>
  );

  const renderDialog = () => {
    switch (variant) {
      case "slideUp":
        return (
          <Dialog
            open={open}
            onClose={handleClose}
            TransitionComponent={TransitionSlide}
            keepMounted
            {...commonDialogProps}
          >
            <DialogTitle sx={{ pb: 1 }}>
              <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
                <Box sx={{ fontSize: "1.2rem" }}>🚀</Box>
                <Typography
                  variant="h6"
                  sx={{ fontWeight: 500, color: textColor }}
                >
                  Slide Up Animation
                </Typography>
              </Box>
            </DialogTitle>
            <DialogContent sx={{ pb: 2 }}>
              <Typography
                variant="body2"
                sx={{ color: "text.secondary", lineHeight: 1.6 }}
              >
                Experience smooth slide-up transitions that feel natural and
                engaging. Perfect for mobile-first interactions.
              </Typography>
            </DialogContent>
            <DialogActions sx={{ px: 3, pb: 3 }}>
              <Button
                onClick={handleClose}
                sx={{
                  borderRadius: 2,
                  backgroundColor: textColor,
                  color: bgColor,
                  "&:hover": {
                    backgroundColor: isDark ? "#e0e0e0" : "#333333",
                  },
                }}
              >
                Got it
              </Button>
            </DialogActions>
          </Dialog>
        );

      case "blur":
        return (
          <Dialog
            open={open}
            TransitionComponent={TransitionFade}
            onClose={handleClose}
            PaperProps={{
              sx: {
                borderRadius: 2,
                width: isMobile ? "90vw" : isTablet ? "80vw" : 480,
                maxWidth: 480,
                backdropFilter: "blur(8px)",
                backgroundColor: bgColor,
                backgroundImage: "none",
                border: `1px solid ${borderColor}`,
                boxShadow: isDark
                  ? "0 5px 20px rgba(0,0,0,0.5)"
                  : "0 5px 20px rgba(0,0,0,0.15)",
              },
            }}
            BackdropProps={{
              sx: {
                backdropFilter: "blur(6px)",
                backgroundColor: "rgba(0,0,0,0.2)",
              },
            }}
          >
            <DialogTitle
              sx={{
                pb: 1,
                display: "flex",
                alignItems: "center",
                justifyContent: "space-between",
              }}
            >
              <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
                <Box sx={{ fontSize: "1.2rem" }}>✨</Box>
                <Typography
                  variant="h6"
                  sx={{ fontWeight: 500, color: textColor }}
                >
                  Glassmorphism Effect
                </Typography>
              </Box>
              <CloseButton onClick={handleClose} />
            </DialogTitle>

            <DialogContent sx={{ pb: 2 }}>
              <Typography
                variant="body2"
                sx={{ color: "text.secondary", lineHeight: 1.6 }}
              >
                Beautiful frosted glass effect with a clean, fast-loading UI.
                Optimized for instant rendering.
              </Typography>
            </DialogContent>

            <DialogActions sx={{ px: 3, pb: 3 }}>
              <Button
                onClick={handleClose}
                sx={{
                  borderRadius: 2,
                  backgroundColor: textColor,
                  color: bgColor,
                  "&:hover": {
                    backgroundColor: isDark ? "#e0e0e0" : "#333333",
                  },
                }}
              >
                Amazing
              </Button>
            </DialogActions>
          </Dialog>
        );

      case "form":
        return (
          <Dialog
            open={open}
            onClose={handleClose}
            TransitionComponent={TransitionGrow}
            {...commonDialogProps}
          >
            <DialogTitle
              sx={{
                pb: 1,
                display: "flex",
                alignItems: "center",
                justifyContent: "space-between",
              }}
            >
              <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
                <Box sx={{ fontSize: "1.2rem" }}>📝</Box>
                <Typography
                  variant="h6"
                  sx={{ fontWeight: 500, color: textColor }}
                >
                  Contact Form
                </Typography>
              </Box>
            </DialogTitle>
            <DialogContent
              sx={{
                display: "flex",
                flexDirection: "column",
                gap: 2.5,
                pt: 2,
                pb: 2,
              }}
            >
              <TextField
                placeholder="Full Name"
                type="text"
                fullWidth
                size="small"
                sx={{
                  "& .MuiOutlinedInput-root": {
                    borderRadius: 2,
                    backgroundColor: isDark
                      ? "rgba(255,255,255,0.05)"
                      : "rgba(0,0,0,0.02)",
                    "& fieldset": {
                      borderColor: borderColor,
                    },
                  },
                  "& .MuiInputBase-input::placeholder": {
                    color: isDark ? "rgba(255,255,255,0.6)" : "rgba(0,0,0,0.6)",
                    opacity: 1,
                  },
                }}
              />

              <TextField
                placeholder="Email Address"
                type="email"
                fullWidth
                size="small"
                sx={{
                  "& .MuiOutlinedInput-root": {
                    borderRadius: 2,
                    backgroundColor: isDark
                      ? "rgba(255,255,255,0.05)"
                      : "rgba(0,0,0,0.02)",
                    "& fieldset": {
                      borderColor: borderColor,
                    },
                  },
                  "& .MuiInputBase-input::placeholder": {
                    color: isDark ? "rgba(255,255,255,0.6)" : "rgba(0,0,0,0.6)",
                    opacity: 1,
                  },
                }}
              />

              <TextField
                placeholder="Your Message"
                multiline
                rows={3}
                fullWidth
                size="small"
                sx={{
                  "& .MuiOutlinedInput-root": {
                    borderRadius: 2,
                    backgroundColor: isDark
                      ? "rgba(255,255,255,0.05)"
                      : "rgba(0,0,0,0.02)",
                    "& fieldset": {
                      borderColor: borderColor,
                    },
                  },
                  "& .MuiInputBase-input::placeholder": {
                    color: isDark ? "rgba(255,255,255,0.6)" : "rgba(0,0,0,0.6)",
                    opacity: 1,
                  },
                }}
              />
            </DialogContent>
            <DialogActions sx={{ px: 3, pb: 3, gap: 1 }}>
              <Button
                onClick={handleClose}
                sx={{
                  borderRadius: 2,
                  color: textColor,
                  border: `1px solid ${borderColor}`,
                }}
              >
                Cancel
              </Button>
              <Button
                onClick={handleClose}
                sx={{
                  borderRadius: 2,
                  backgroundColor: textColor,
                  color: bgColor,
                  "&:hover": {
                    backgroundColor: isDark ? "#e0e0e0" : "#333333",
                  },
                }}
              >
                Send Message
              </Button>
            </DialogActions>
          </Dialog>
        );

      case "info":
        return (
          <Dialog
            open={open}
            onClose={handleClose}
            TransitionComponent={TransitionSlide}
            {...commonDialogProps}
          >
            <DialogContent
              sx={{ textAlign: "center", py: 4, position: "relative" }}
            >
              <CloseButton
                onClick={handleClose}
                style={{
                  position: "absolute",
                  top: 8,
                  right: 8,
                }}
              />
              <Box sx={{ fontSize: "3rem", mb: 2 }}>💡</Box>
              <Typography
                variant="h6"
                sx={{ fontWeight: 500, mb: 2, color: textColor }}
              >
                Quick Tip
              </Typography>
              <Typography
                variant="body2"
                sx={{ color: "text.secondary", lineHeight: 1.6, mb: 3 }}
              >
                Did you know? You can use keyboard shortcuts to navigate faster.
                Press Ctrl+K to open quick search.
              </Typography>
              <Button
                onClick={handleClose}
                sx={{
                  backgroundColor: textColor,
                  color: bgColor,
                  minWidth: 120,
                  borderRadius: 2,
                  "&:hover": {
                    backgroundColor: isDark ? "#e0e0e0" : "#333333",
                  },
                }}
              >
                Thanks!
              </Button>
            </DialogContent>
          </Dialog>
        );

      case "fullscreen":
        return (
          <Dialog
            open={open}
            onClose={handleClose}
            fullScreen
            TransitionComponent={TransitionSlide}
            PaperProps={{
              sx: {
                backgroundColor: bgColor,
                backgroundImage: "none",
              },
            }}
          >
            <Box
              sx={{
                height: "100vh",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                flexDirection: "column",
                p: 4,
                textAlign: "center",
                position: "relative",
              }}
            >
              <CloseButton
                onClick={handleClose}
                style={{
                  position: "absolute",
                  top: 16,
                  right: 16,
                  width: 40,
                  height: 40,
                }}
              />
              <Box sx={{ fontSize: "62px", mb: 2 }}>🎯</Box>
              <Typography
                variant="h2"
                sx={{
                  fontWeight: 500,
                  mb: 1,
                  color: textColor,
                }}
              >
                Focus Mode
              </Typography>
              <Typography
                variant="h6"
                sx={{
                  fontWeight: 400,
                  color: "text.secondary",
                  maxWidth: 500,
                  lineHeight: 1.6,
                }}
              >
                Perfect for presentations, forms, or detailed views.
              </Typography>
            </Box>
          </Dialog>
        );

      case "sidebar":
        return (
          <Dialog
            open={open}
            onClose={handleClose}
            TransitionComponent={TransitionSlide}
            keepMounted
            sx={{
              "& .MuiDialog-container": {
                justifyContent: "flex-start",
                alignItems: "stretch",
              },
            }}
            PaperProps={{
              sx: {
                width: isMobile ? "260px" : "300px",
                height: "100vh",
                borderRadius: 2,
                backgroundColor: bgColor,
                backgroundImage: "none",
                borderRight: `1px solid ${borderColor}`,
              },
            }}
          >
            <Box sx={{ p: 2, height: "100%" }}>
              <Box
                sx={{
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "space-between",
                  mb: 2,
                }}
              >
                <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
                  <RxGear size={20} color={textColor} />
                  <Typography
                    variant="subtitle1"
                    sx={{ fontWeight: 500, color: textColor }}
                  >
                    Settings
                  </Typography>
                </Box>
                <CloseButton onClick={handleClose} />
              </Box>

              <List
                sx={{
                  "& .MuiListItem-root": {
                    borderRadius: 2,
                    padding: "8px",
                    mb: 0.5,
                  },
                }}
              >
                <ListItem
                  sx={{
                    "&:hover": { backgroundColor: "action.hover" },
                    cursor: "pointer",
                  }}
                >
                  <ListItemIcon sx={{ minWidth: 32 }}>
                    <RxDashboard size={18} color={textColor} />
                  </ListItemIcon>
                  <ListItemText
                    primary="Dashboard"
                    secondary="Main overview"
                    primaryTypographyProps={{
                      color: textColor,
                      fontSize: 14,
                      fontWeight: 500,
                    }}
                    secondaryTypographyProps={{
                      fontSize: 12,
                      opacity: 0.7,
                    }}
                  />
                  <RxChevronRight size={16} color={textColor} opacity={0.6} />
                </ListItem>

                <Divider sx={{ my: 0.5 }} />

                <ListItem
                  sx={{
                    "&:hover": { backgroundColor: "action.hover" },
                    cursor: "pointer",
                  }}
                >
                  <ListItemIcon sx={{ minWidth: 32 }}>
                    <RxPerson size={18} color={textColor} />
                  </ListItemIcon>
                  <ListItemText
                    primary="Profile"
                    secondary="Personal settings"
                    primaryTypographyProps={{
                      color: textColor,
                      fontSize: 14,
                      fontWeight: 500,
                    }}
                    secondaryTypographyProps={{
                      fontSize: 12,
                      opacity: 0.7,
                    }}
                  />
                  <RxChevronRight size={16} color={textColor} opacity={0.6} />
                </ListItem>

                <Divider sx={{ my: 0.5 }} />

                <ListItem
                  sx={{
                    "&:hover": { backgroundColor: "action.hover" },
                    cursor: "pointer",
                  }}
                >
                  <ListItemIcon sx={{ minWidth: 32 }}>
                    <RxBell size={18} color={textColor} />
                  </ListItemIcon>
                  <ListItemText
                    primary="Notifications"
                    secondary="Manage alerts"
                    primaryTypographyProps={{
                      color: textColor,
                      fontSize: 14,
                      fontWeight: 500,
                    }}
                    secondaryTypographyProps={{
                      fontSize: 12,
                      opacity: 0.7,
                    }}
                  />
                  <RxChevronRight size={16} color={textColor} opacity={0.6} />
                </ListItem>
              </List>
            </Box>
          </Dialog>
        );

      case "notification":
        return (
          <AnimatePresence>
            {open && (
              <MotionBox
                initial={{ opacity: 0, y: -50, scale: 0.95 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                exit={{ opacity: 0, y: -50, scale: 0.95 }}
                transition={{ type: "spring", stiffness: 500, damping: 30 }}
                sx={{
                  position: "fixed",
                  top: 20,
                  right: 20,
                  zIndex: 9999,
                  width: isMobile ? "calc(100vw - 40px)" : 420,
                  maxWidth: "calc(100vw - 40px)",
                  backgroundColor: bgColor,
                  border: `1px solid ${borderColor}`,
                  borderRadius: 2,
                  boxShadow: isDark
                    ? "0 25px 50px -12px rgba(0, 0, 0, 0.8)"
                    : "0 25px 50px -12px rgba(0, 0, 0, 0.25)",
                  p: 2,
                }}
              >
                <Box sx={{ display: "flex", alignItems: "flex-start", gap: 2 }}>
                  <Box
                    sx={{
                      width: 32,
                      height: 32,
                      borderRadius: "50%",
                      backgroundColor: "#10b981",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      flexShrink: 0,
                    }}
                  >
                    <RxCheck size={20} color="white" />
                  </Box>

                  <Box sx={{ flex: 1, minWidth: 0 }}>
                    <Typography
                      variant="body2"
                      sx={{ fontWeight: 500, color: textColor, mb: 0.5 }}
                    >
                      Successfully saved! 🎉
                    </Typography>
                    <Typography
                      variant="caption"
                      sx={{ color: "text.secondary", lineHeight: 1.5 }}
                    >
                      Your changes have been saved and will take effect
                      immediately.
                    </Typography>
                  </Box>

                  <CloseButton onClick={handleClose} />
                </Box>
              </MotionBox>
            )}
          </AnimatePresence>
        );

      default:
        return (
          <Dialog
            open={open}
            onClose={handleClose}
            TransitionComponent={TransitionFade}
            {...commonDialogProps}
          >
            <DialogTitle sx={{ pb: 1 }}>
              <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
                <Box sx={{ fontSize: "1.2rem" }}>💬</Box>
                <Typography
                  variant="h6"
                  sx={{ fontWeight: 500, color: textColor }}
                >
                  Simple Dialog
                </Typography>
              </Box>
            </DialogTitle>
            <DialogContent sx={{ pb: 2 }}>
              <Typography
                variant="body2"
                sx={{ color: "text.secondary", lineHeight: 1.6 }}
              >
                Clean and minimal dialog design with consistent spacing and
                typography. Perfect for simple interactions.
              </Typography>
            </DialogContent>
            <DialogActions sx={{ px: 3, pb: 3 }}>
              <Button
                onClick={handleClose}
                sx={{
                  borderRadius: 2,
                  backgroundColor: textColor,
                  color: bgColor,
                  "&:hover": {
                    backgroundColor: isDark ? "#e0e0e0" : "#333333",
                  },
                }}
              >
                Understood
              </Button>
            </DialogActions>
          </Dialog>
        );
    }
  };

  return (
    <Box sx={{ display: "flex", justifyContent: "center" }}>
      <Button
        variant="outlined"
        onClick={handleOpen}
        sx={{
          borderColor: borderColor,
          color: textColor,
          borderRadius: 2,
          px: 3,
          py: 1,
          fontWeight: 500,
          "&:hover": {
            borderColor: textColor,
            backgroundColor: isDark
              ? "rgba(255,255,255,0.05)"
              : "rgba(0,0,0,0.05)",
          },
        }}
      >
        {getButtonText()}
      </Button>
      {renderDialog()}
    </Box>
  );
};

export default DialogVariants;

