import React, { useState, useCallback, useMemo } from "react";
import {
  Box,
  Paper,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TablePagination,
  Typography,
  IconButton,
  Checkbox,
  useTheme,
  alpha,
  Tooltip,
  CircularProgress,
  Collapse,
} from "@mui/material";
import { motion } from "motion/react";
import {
  LuChevronDown,
  LuArrowUpDown,
  LuSearch,
  LuFilter,
} from "react-icons/lu";

const MotionTableRow = motion.create(TableRow);
const MotionPaper = motion.create(Paper);

const createData = (id, name, role, status, progress, date) => ({
  id,
  name,
  role,
  status,
  progress,
  date,
  details: {
    email: `${name.toLowerCase().replace(" ", ".")}@example.com`,
    phone: "+1 (555) 000-0000",
    address: "123 Business Street, Tech City, 12345",
    department: "Technology",
    joinDate: "2023-01-01",
    projects: ["Project Alpha", "Project Beta"],
  },
});

const sampleData = [
  createData(1, "Alex Thompson", "Developer", "Active", 75, "2025-01-01"),
  createData(2, "Sarah Wilson", "Designer", "Inactive", 45, "2025-01-02"),
  createData(3, "Michael Chen", "Manager", "Active", 90, "2025-01-03"),
  createData(4, "Emily Davis", "Analyst", "Active", 60, "2025-01-04"),
  createData(5, "James Wilson", "Developer", "Inactive", 30, "2025-01-05"),
];

const TableVariants = ({ variant = "modern" }) => {
  const theme = useTheme();
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(5);
  const [selected, setSelected] = useState([]);
  const [expandedRow, setExpandedRow] = useState(null);
  const [sortConfig, setSortConfig] = useState({ key: null, direction: "asc" });
  const [loading, setLoading] = useState(false);

  const sortedData = useMemo(() => {
    if (!sortConfig.key) return sampleData;
    return [...sampleData].sort((a, b) => {
      const aVal = a[sortConfig.key];
      const bVal = b[sortConfig.key];
      if (typeof aVal === "string") {
        return sortConfig.direction === "asc"
          ? aVal.localeCompare(bVal)
          : bVal.localeCompare(aVal);
      }
      return sortConfig.direction === "asc" ? aVal - bVal : bVal - aVal;
    });
  }, [sortConfig]);

  const handleSort = (key) => {
    setSortConfig((current) => ({
      key,
      direction:
        current.key === key && current.direction === "asc" ? "desc" : "asc",
    }));
  };

  const handleSelectAllClick = useCallback((event) => {
    setSelected(event.target.checked ? sampleData.map((row) => row.id) : []);
  }, []);

  const handleSelectClick = useCallback((id) => {
    setSelected((prev) => {
      const selectedIndex = prev.indexOf(id);
      if (selectedIndex === -1) return [...prev, id];
      return prev.filter((itemId) => itemId !== id);
    });
  }, []);

  const StatusBadge = ({ status }) => (
    <Box
      component={motion.div}
      initial={{ scale: 0.8, opacity: 0 }}
      animate={{ scale: 1, opacity: 1 }}
      transition={{ duration: 0.3, ease: "easeOut" }}
      sx={{
        display: "inline-flex",
        px: 1.5,
        py: 0.75,
        borderRadius: 2,
        bgcolor:
          status === "Active"
            ? alpha(theme.palette.success.main, 0.1)
            : alpha(theme.palette.error.main, 0.1),
        color:
          status === "Active"
            ? theme.palette.success.main
            : theme.palette.error.main,
        fontWeight: 500,
      }}
    >
      {status}
    </Box>
  );

  const ProgressBar = ({ value, delay = 0 }) => (
    <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
      <Box
        sx={{
          flexGrow: 1,
          bgcolor: alpha(theme.palette.primary.main, 0.1),
          borderRadius: 1,
          overflow: "hidden",
        }}
      >
        <Box
          component={motion.div}
          initial={{ width: 0 }}
          animate={{ width: `${value}%` }}
          transition={{ duration: 0.8, delay, ease: "easeOut" }}
          sx={{
            height: 6,
            bgcolor: theme.palette.primary.main,
            borderRadius: 1,
          }}
        />
      </Box>
      <Typography variant="body2" color="text.secondary" sx={{ minWidth: 40 }}>
        {value}%
      </Typography>
    </Box>
  );

  const renderVariant = () => {
    switch (variant) {
      case "minimal":
        return (
          <MotionPaper
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.3, ease: "easeOut" }}
            elevation={0}
            sx={{
              overflow: "hidden",
              backgroundImage:
                "linear-gradient(rgba(255, 255, 255, 0.05), rgba(255, 255, 255, 0.05)) !important",
              border: `1px solid ${theme.palette.divider}`,
              boxShadow: "0 4px 20px rgba(0, 0, 0, 0.1)",
              borderRadius: 2,
            }}
          >
            <TableContainer
              sx={{
                "&::-webkit-scrollbar": {
                  display: "none",
                },
                msOverflowStyle: "none",
                scrollbarWidth: "none",
              }}
            >
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell>Name</TableCell>
                    <TableCell>Role</TableCell>
                    <TableCell>Status</TableCell>
                    <TableCell align="right">Progress</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {sortedData
                    .slice(page * rowsPerPage, page * rowsPerPage + rowsPerPage)
                    .map((row, index) => (
                      <MotionTableRow
                        key={row.id}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{
                          delay: index * 0.05,
                          duration: 0.3,
                          ease: "easeOut",
                        }}
                        sx={{
                          "&:hover": {
                            bgcolor: alpha(theme.palette.primary.main, 0.04),
                          },
                        }}
                      >
                        <TableCell>{row.name}</TableCell>
                        <TableCell>{row.role}</TableCell>
                        <TableCell>
                          <StatusBadge status={row.status} />
                        </TableCell>
                        <TableCell align="right">
                          <ProgressBar
                            value={row.progress}
                            delay={index * 0.05}
                          />
                        </TableCell>
                      </MotionTableRow>
                    ))}
                </TableBody>
              </Table>
            </TableContainer>
            <TablePagination
              component="div"
              count={sampleData.length}
              page={page}
              rowsPerPage={rowsPerPage}
              onPageChange={(e, newPage) => setPage(newPage)}
              rowsPerPageOptions={[5, 10, 15, 25]}
              onRowsPerPageChange={(e) => {
                setRowsPerPage(parseInt(e.target.value, 10));
                setPage(0);
              }}
              labelDisplayedRows={({ from, to, count }) =>
                `${from}-${to} of ${count !== -1 ? count : `more than ${to}`}`
              }
              SelectProps={{
                IconComponent: LuChevronDown,
                native: false,
                renderValue: (value) => `${value}`,
                MenuProps: {
                  PaperProps: {
                    sx: { maxHeight: 200 },
                  },
                },
                sx: {
                  fontSize: "16px !important",
