                              sx={{
                                transition: "transform 0.2s",
                                transform:
                                  expandedRow === row.id
                                    ? "rotate(-180deg)"
                                    : "none",
                              }}
                            >
                              <LuChevronDown />
                            </IconButton>
                          </TableCell>
                          <TableCell>
                            <Box
                              component={motion.div}
                              initial={{ opacity: 0, scale: 0.95 }}
                              animate={{ opacity: 1, scale: 1 }}
                              transition={{ duration: 0.3, ease: "easeOut" }}
                            >
                              <Typography variant="subtitle2">
                                {row.name}
                              </Typography>
                              <Typography
                                variant="body2"
