                                          {key.charAt(0).toUpperCase() +
                                            key.slice(1)}
                                        </Typography>
                                        <Typography>
                                          {Array.isArray(value)
                                            ? value.join(", ")
                                            : value}
                                        </Typography>
                                      </Box>
                                    )
                                  )}
                                </Box>
                              </Box>
                            </Collapse>
                          </TableCell>
                        </TableRow>
                      </React.Fragment>
                    ))}
                </TableBody>
              </Table>
            </TableContainer>
            <TablePagination
              component="div"
              count={sampleData.length}
              page={page}
              rowsPerPage={rowsPerPage}
              onPageChange={(e, newPage) => setPage(newPage)}
              rowsPerPageOptions={[5, 10, 15, 25]}
              onRowsPerPageChange={(e) => {
                setRowsPerPage(parseInt(e.target.value, 10));
                setPage(0);
              }}
              labelDisplayedRows={({ from, to, count }) =>
                `${from}-${to} of ${count !== -1 ? count : `more than ${to}`}`
              }
              SelectProps={{
                IconComponent: LuChevronDown,
                native: false,
                renderValue: (value) => `${value}`,
                MenuProps: {
                  PaperProps: {
                    sx: { maxHeight: 200 },
                  },
                },
                sx: {
                  fontSize: "16px !important",
                },
              }}
            />
          </MotionPaper>
        );

      case "modern":
      default:
        return (
          <MotionPaper
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.3, ease: "easeOut" }}
            sx={{
              overflow: "hidden",
              bgcolor: "background.paper",
              border: `1px solid ${theme.palette.divider}`,
              boxShadow: "0 4px 20px rgba(0, 0, 0, 0.1)",
              borderRadius: 2,
            }}
          >
            <TableContainer
              sx={{
                "&::-webkit-scrollbar": {
                  display: "none",
                },
                msOverflowStyle: "none",
                scrollbarWidth: "none",
              }}
            >
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell padding="checkbox">
                      <Checkbox
                        indeterminate={
                          selected.length > 0 &&
                          selected.length < sampleData.length
                        }
                        checked={selected.length === sampleData.length}
                        onChange={handleSelectAllClick}
                      />
                    </TableCell>
                    {[
                      { key: "name", label: "Name" },
                      { key: "role", label: "Role" },
                      { key: "status", label: "Status" },
                      { key: "progress", label: "Progress" },
                      { key: "date", label: "Date" },
                    ].map((header) => (
                      <TableCell
                        key={header.key}
                        sortDirection={
                          sortConfig.key === header.key
                            ? sortConfig.direction
                            : false
                        }
                      >
                        <Box
                          sx={{
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center",
                            gap: 0.5,
                            cursor: "pointer",
                            userSelect: "none",
                            "&:hover": {
                              color: theme.palette.primary.main,
                            },
                          }}
                          onClick={() => handleSort(header.key)}
                        >
                          <Box
                            component="span"
                            sx={{
                              display: "inline-flex",
                              alignItems: "center",
                              lineHeight: 1,
                            }}
                          >
                            {header.label}
                          </Box>
                          <Box
                            component={motion.div}
                            sx={{
                              display: "inline-flex",
                              alignItems: "center",
                            }}
                            animate={{
                              rotate:
                                sortConfig.key === header.key
                                  ? sortConfig.direction === "desc"
                                    ? 180
                                    : 0
                                  : 0,
                            }}
                            transition={{
                              duration: 0.3,
                              ease: "easeOut",
                            }}
                          >
                            <LuArrowUpDown size={16} />
                          </Box>
                        </Box>
                      </TableCell>
                    ))}
                  </TableRow>
                </TableHead>
                <TableBody>
                  {loading ? (
                    <TableRow>
                      <TableCell colSpan={6} align="center" sx={{ py: 8 }}>
                        <CircularProgress size={40} />
                      </TableCell>
                    </TableRow>
                  ) : (
                    sortedData
                      .slice(
                        page * rowsPerPage,
                        page * rowsPerPage + rowsPerPage
                      )
                      .map((row, index) => {
                        const isSelected = selected.indexOf(row.id) !== -1;
                        return (
                          <MotionTableRow
                            key={row.id}
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{
                              delay: index * 0.05,
                              duration: 0.3,
                              ease: "easeOut",
                            }}
                            sx={{
                              bgcolor: isSelected
                                ? alpha(theme.palette.primary.main, 0.08)
                                : "transparent",
                              "&:hover": {
                                bgcolor: isSelected
                                  ? alpha(theme.palette.primary.main, 0.12)
                                  : alpha(theme.palette.primary.main, 0.04),
                              },
                            }}
                          >
                            <TableCell padding="checkbox">
                              <Checkbox
                                checked={isSelected}
                                onChange={() => handleSelectClick(row.id)}
                              />
                            </TableCell>
                            <TableCell>
                              <Box
                                component={motion.div}
                                initial={{ opacity: 0, scale: 0.95 }}
                                animate={{ opacity: 1, scale: 1 }}
                                transition={{ duration: 0.3, ease: "easeOut" }}
                              >
                                <Typography variant="subtitle2">
                                  {row.name}
                                </Typography>
                                <Typography
                                  variant="body2"
                                  color="text.secondary"
                                >
                                  {row.details.email}
                                </Typography>
                              </Box>
                            </TableCell>
                            <TableCell>{row.role}</TableCell>
                            <TableCell>
                              <StatusBadge status={row.status} />
                            </TableCell>
                            <TableCell>
                              <ProgressBar
                                value={row.progress}
                                delay={index * 0.05}
                              />
                            </TableCell>
                            <TableCell sx={{ minWidth: "120px" }}>
                              {row.date}
                            </TableCell>
                          </MotionTableRow>
                        );
                      })
                  )}
                </TableBody>
              </Table>
            </TableContainer>
            <TablePagination
              component="div"
              count={sampleData.length}
              page={page}
              rowsPerPage={rowsPerPage}
              onPageChange={(e, newPage) => setPage(newPage)}
              rowsPerPageOptions={[5, 10, 15, 25]}
              onRowsPerPageChange={(e) => {
                setRowsPerPage(parseInt(e.target.value, 10));
                setPage(0);
              }}
              labelDisplayedRows={({ from, to, count }) =>
                `${from}-${to} of ${count !== -1 ? count : `more than ${to}`}`
              }
              SelectProps={{
                IconComponent: LuChevronDown,
                native: false,
                renderValue: (value) => `${value}`,
                MenuProps: {
                  PaperProps: {
                    sx: { maxHeight: 200 },
                  },
                },
                sx: {
                  fontSize: "16px !important",
                },
              }}
            />
          </MotionPaper>
        );
    }
  };

  return renderVariant();
};


export default TableVariants;

