                  transform: "translateY(-50%)",
                  pointerEvents: "none",
                }}
              >
                <AnimatePresence mode="wait">
                  <motion.div
                    key={placeholderIndex}
                    initial={fadeScaleVariant.initial}
                    animate={fadeScaleVariant.animate}
                    exit={fadeScaleVariant.exit}
                  >
                    <Typography
                      variant="body2"
                      sx={{ color: colors.textSecondary }}
                    >
                      {getCurrentPlaceholder()}
                    </Typography>
                  </motion.div>
                </AnimatePresence>
              </Box>
            )}
          </Box>
        );

      case "currency":
        return (
          <Box sx={{ position: "relative", width: "100%" }}>
            <TextField
              fullWidth
              value={value}
              onChange={(e) => setValue(e.target.value)}
              onFocus={() => setIsFocused(true)}
              onBlur={() => setIsFocused(false)}
              InputProps={{
                startAdornment: (
                  <InputAdornment
                    position="start"
                    sx={{
                      m: 0,
                      height: "100%",
                    }}
                  >
                    <Box
                      sx={{
                        height: "42px",
                        display: "flex",
                        alignItems: "center",
                        px: "10px",
                        backgroundColor: colors.addon,
                        borderRadius: "6px",
                        border: `1px solid ${colors.border}`,
                      }}
                    >
                      <Typography
                        sx={{
                          fontSize: "13px",
                          fontWeight: 500,
                          color: colors.textSecondary,
                          lineHeight: "1",
                        }}
                      >
                        €
                      </Typography>
                    </Box>
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment
                    position="end"
                    sx={{
                      m: 0,
                      height: "100%",
                    }}
                  >
                    <Box
                      sx={{
                        height: "42px",
                        display: "flex",
                        alignItems: "center",
                        px: "10px",
                        backgroundColor: colors.addon,
                        borderRadius: "6px",
                        border: `1px solid ${colors.border}`,
                      }}
                    >
                      <Typography
                        sx={{
                          fontSize: "13px",
                          fontWeight: 500,
                          color: colors.textSecondary,
                          lineHeight: "1",
                        }}
                      >
                        EUR
                      </Typography>
                    </Box>
                  </InputAdornment>
                ),
              }}
              sx={{
                "& .MuiOutlinedInput-root": {
                  height: "42px",
                  borderRadius: "10px",
                  backgroundColor: colors.background,
                  px: 0,
                  "& fieldset": {
                    borderColor: colors.border,
                  },
                  "&:hover fieldset": {
                    borderColor: colors.borderFocus,
                  },
                  "&.Mui-focused fieldset": {
                    borderColor: colors.borderFocus,
                    borderWidth: "2px",
                  },
                },
                "& .MuiInputBase-input": {
                  color: colors.text,
                  fontSize: "14px",
                  px: 1,
                },
              }}
            />

            {!isFocused && !value && (
              <Box
                sx={{
                  position: "absolute",
                  left: 60,
                  top: "50%",
                  transform: "translateY(-50%)",
                  pointerEvents: "none",
                }}
              >
                <AnimatePresence mode="wait">
                  <motion.div
                    key={placeholderIndex}
                    initial={{ opacity: 0, rotateX: 20 }}
                    animate={{
                      opacity: 1,
                      rotateX: 0,
                      transition: { duration: 0.22 },
                    }}
                    exit={{
                      opacity: 0,
                      rotateX: -20,
                      transition: { duration: 0.18 },
                    }}
                  >
                    <Typography
                      variant="body2"
                      sx={{ color: colors.textSecondary }}
                    >
                      {getCurrentPlaceholder()}
                    </Typography>
                  </motion.div>
                </AnimatePresence>
              </Box>
            )}
          </Box>
        );

      case "aiPrompt":
        return (
          <Box sx={{ position: "relative", width: "100%" }}>
            <Box sx={{ position: "absolute", bottom: 8, left: 8, zIndex: 2 }}>
              <FormControl size="small" sx={{ minWidth: 120 }}>
                <Select
                  value={selectedModel}
                  onChange={(e) => setSelectedModel(e.target.value)}
                  IconComponent={FiChevronDown}
                  sx={{
                    height: 32,
                    fontSize: "0.875rem",
                    "& .MuiOutlinedInput-notchedOutline": { border: "none" },
                    "& .MuiSelect-select": {
                      color: colors.text,
                      fontSize: "14px",
                      fontWeight: 500,
                      backgroundColor: colors.addon,
                      borderRadius: "8px",
                      px: 1.5,
                      py: 0.5,
                    },
                  }}
                  MenuProps={{
                    PaperProps: {
                      sx: {
                        borderRadius: "8px",
                        mt: 1,
                        backgroundColor: isDark ? "#1e1e1e" : "#ffffff",
                        boxShadow: "0px 4px 12px rgba(0,0,0,0.1)",
                        fontSize: "0.875rem",
                      },
                    },
                  }}
                >
                  {aiModels.map((model) => (
                    <MenuItem
                      key={model.value}
                      value={model.value}
                      sx={{
                        fontSize: "15px !important",
                        minHeight: "36px",
                        "&.Mui-selected": {
                          backgroundColor: isDark ? "#2a2a2a" : "#f5f5f5",
                        },
                      }}
                    >
                      {model.label}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Box>

            <Box
              sx={{
                position: "absolute",
                bottom: 8,
                right: 8,
                display: "flex",
                gap: 1,
                zIndex: 2,
              }}
            >
              <motion.div {...subtleButtonTap}>
                <IconButton
                  size="small"
                  sx={{
                    color: isDark ? "#000" : "#FFF",
                    backgroundColor: isDark ? "#FFF" : "#000",
                    borderRadius: "8px",
                    p: "8px",
                    "&:hover": {
                      backgroundColor: isDark ? "#FFF" : "#000",
                    },
                  }}
                >
                  <FiPaperclip size={18} />
                </IconButton>
              </motion.div>
              <motion.div {...subtleButtonTap}>
                <IconButton
                  size="small"
                  sx={{
                    color: isDark ? "#000" : "#FFF",
                    backgroundColor: isDark ? "#FFF" : "#000",
                    borderRadius: "8px",
                    p: "8px",
                    "&:hover": {
                      backgroundColor: isDark ? "#FFF" : "#000",
                    },
                  }}
                >
                  <FiArrowUp size={18} />
                </IconButton>
              </motion.div>
            </Box>

            <TextField
              fullWidth
              multiline
              minRows={1}
              maxRows={4}
              value={value}
              onChange={(e) => setValue(e.target.value)}
              onFocus={() => setIsFocused(true)}
              onBlur={() => setIsFocused(false)}
              placeholder=" "
              InputProps={{}}
              sx={{
                "& .MuiOutlinedInput-root": {
                  minHeight: 100,
                  borderRadius: "12px",
                  backgroundColor: colors.background,
                  alignItems: "flex-start",
                  px: 1,
                  pt: 1,
                  pb: 6,
                  "& fieldset": {
                    borderColor: colors.border,
                  },
                  "&:hover fieldset": {
                    borderColor: colors.borderFocus,
                  },
                  "&.Mui-focused fieldset": {
                    borderColor: colors.borderFocus,
                    borderWidth: "2px",
                  },
                },
                "& .MuiInputBase-input": {
                  color: colors.text,
                  fontSize: "0.875rem",
                  lineHeight: 1.5,
                  padding: 0,
                  ml: 1,
                  mt: 1,
                },
                "& .MuiInputBase-inputMultiline": {
                  padding: 0,
                  mb: 0,
                },
              }}
            />

            {!isFocused && !value && (
              <Box
                sx={{
                  position: "absolute",
                  left: 10,
                  top: 8,
                  pointerEvents: "none",
                  zIndex: 1,
                }}
              >
                <AnimatePresence mode="wait">
                  <motion.div
                    key={placeholderIndex}
                    initial={fadeUpVariant.initial}
                    animate={fadeUpVariant.animate}
                    exit={fadeUpVariant.exit}
                  >
                    <Typography
                      variant="body2"
                      sx={{ color: colors.textSecondary }}
                    >
                      {getCurrentPlaceholder()}
                    </Typography>
                  </motion.div>
                </AnimatePresence>
              </Box>
            )}
          </Box>
        );

      case "otp":
        return (
          <Box sx={{ position: "relative", width: "100%" }}>
            <Box
              sx={{
                display: "flex",
                gap: { xs: 1, sm: 1.5 },
                justifyContent: "center",
                alignItems: "center",
              }}
            >
              {otpValues.map((digit, index) => (
                <React.Fragment key={index}>
                  <motion.div
                    initial={{ opacity: 0, y: 6 }}
                    animate={{
                      opacity: 1,
                      y: 0,
                      transition: { duration: 0.12, delay: index * 0.03 },
                    }}
                    whileHover={{ y: -2 }}
                    whileTap={{ scale: 0.98 }}
                  >
                    <TextField
                      inputProps={{
                        maxLength: 1,
                        style: {
                          textAlign: "center",
                          fontSize: "16px",
                          fontWeight: 500,
                          padding: "10px 0",
                        },
                        autoComplete: "one-time-code",
                      }}
                      value={digit}
                      onChange={(e) => {
                        const newValue = e.target.value.replace(/[^0-9]/g, "");
                        if (newValue.length <= 1) {
                          const newOtpValues = [...otpValues];
                          newOtpValues[index] = newValue;
                          setOtpValues(newOtpValues);

                          if (newValue && index < 5) {
                            document
                              .querySelector(`input[data-index="${index + 1}"]`)
                              ?.focus();
                          }
                        }
                      }}
                      onPaste={(e) => {
                        e.preventDefault();
                        const paste = e.clipboardData
                          .getData("text")
                          .replace(/[^0-9]/g, "");
                        if (paste) {
                          const digits = paste.slice(0, 6).split("");
                          setOtpValues([
                            ...digits,
                            ...Array(6 - digits.length).fill(""),
                          ]);
                        }
                      }}
                      onKeyDown={(e) => {
                        if (e.key === "Backspace" && !digit && index > 0) {
                          document
                            .querySelector(`input[data-index="${index - 1}"]`)
                            ?.focus();
                        }
                        if (e.key === "v" && (e.ctrlKey || e.metaKey)) {
                          e.preventDefault();
                          navigator.clipboard.readText().then((text) => {
                            const digits = text
                              .replace(/[^0-9]/g, "")
                              .slice(0, 6)
                              .split("");
                            setOtpValues([
                              ...digits,
                              ...Array(6 - digits.length).fill(""),
                            ]);
                          });
                        }
                      }}
                      onFocus={() => setIsFocused(true)}
                      onBlur={() => setIsFocused(false)}
                      sx={{
                        width: { xs: 40, sm: 46 },
                        height: { xs: 40, sm: 46 },
                        "& .MuiOutlinedInput-root": {
                          borderRadius: "8px",
                          backgroundColor: digit
                            ? colors.addon
                            : colors.background,
                          "& fieldset": {
                            borderColor: colors.border,
                            borderWidth: "1px",
                          },
                          "&:hover fieldset": {
                            borderColor: colors.border,
                          },
                          "&.Mui-focused fieldset": {
                            borderColor: colors.border,
                            borderWidth: "1px",
                          },
                        },
                        "& .MuiInputBase-input": { color: colors.text },
                      }}
                      inputRef={(input) =>
                        input?.setAttribute("data-index", index)
                      }
                    />
                  </motion.div>

                  {index === 2 && (
                    <Box
                      sx={{
                        display: "flex",
                        alignItems: "center",
                        height: { xs: 40, sm: 46 },
                      }}
                    >
                      <Box
                        sx={{
                          width: 8,
                          height: 1.5,
                          backgroundColor: colors.textSecondary,
                          borderRadius: 1,
                          opacity: 0.4,
                        }}
                      />
                    </Box>
                  )}
                </React.Fragment>
              ))}
            </Box>

            <Box
              sx={{
                display: "flex",
                justifyContent: "center",
                mt: 2,
                gap: 0.5,
              }}
            >
              {otpValues.map((digit, index) => (
                <motion.div
                  key={index}
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  transition={{ duration: 0.12 }}
                >
                  <Box
                    sx={{
                      width: 6,
                      height: 6,
                      borderRadius: "50%",
                      backgroundColor: digit
                        ? isDark
                          ? "#ffffff"
                          : "#000000"
                        : isDark
                          ? "#333333"
                          : "#e0e0e0",
                    }}
                  />
                </motion.div>
              ))}
            </Box>
          </Box>
        );

      default:
        return null;
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.22 }}
    >
      <Box sx={{ width: "100%", maxWidth: 600, margin: "0 auto", padding: 2 }}>
        {renderVariant()}
      </Box>
    </motion.div>
  );
};

export default TextFieldVariants;

